-- ============================================================================
-- 1. Survey Analytics Dashboard (data plugin)
-- ============================================================================

INSERT INTO skill_registry (plugin_name, skill_name, team_function, description, content, is_active)
SELECT
  'data',
  'survey-analytics',
  'data',
  'Build an interactive survey analytics dashboard with response rates, cross-tab analysis, demographic breakdowns, and trend tracking.',
  E'---\nname: survey-analytics\ndescription: Build an interactive survey analytics dashboard with response rates, cross-tab analysis, demographic breakdowns, and trend tracking. Use when analyzing survey results, building a respondent overview, visualizing Likert scales, or tracking NPS/CSAT over time.\nargument-hint: "<survey description or data source>"\n---\n\n# /survey-analytics - Survey Analytics Dashboard\n\nBuild a self-contained interactive HTML dashboard for survey data analysis — response rates, cross-tabulations, demographic breakdowns, and longitudinal trend tracking.\n\n## Usage\n\n```\n/survey-analytics <description of survey or data source>\n```\n\n## Workflow\n\n### 1. Understand the Survey\n\nDetermine:\n- **Survey type**: Employee engagement, CSAT, NPS, market research, product feedback, academic\n- **Question types**: Likert scale, multiple choice, open-ended, ranking, matrix\n- **Demographics collected**: Age, gender, department, region, tenure, role level\n- **Time dimension**: One-time snapshot or recurring (quarterly, annual)\n- **Sample size**: Total responses, response rate target\n\n### 2. Gather the Data\n\n**If data is provided:** Parse CSV/JSON, identify question columns vs demographic columns, detect scales.\n\n**If working from description:** Generate a realistic sample dataset with 200-500 respondents. Note clearly that sample data is in use.\n\n### 3. Dashboard Layout\n\n```\n+------------------------------------------------------+\n| Survey Analytics Dashboard           [Filters]       |\n+------------+------------+------------+---------------+\n| Responses  | Response   | Completion | Avg Score /   |\n| Collected  | Rate       | Rate       | NPS           |\n+------------+------------+------------+---------------+\n| Response Trend         | Score Distribution          |\n| (line over time)       | (stacked bar / histogram)   |\n+------------------------+-----------------------------+\n| Cross-Tab Heatmap      | Demographic Breakdown       |\n| (question x segment)   | (grouped bar)               |\n+------------------------+-----------------------------+\n| Respondent Detail Table (sortable, filterable)       |\n+------------------------------------------------------+\n```\n\n### 4. Key Visualizations\n\n| Chart | Purpose |\n|-------|--------|\n| Line | Response volume over time |\n| Stacked bar | Likert distribution per question |\n| Grouped bar | Scores by demographic segment |\n| Doughnut | Demographic composition |\n| Heatmap | Cross-tab question x segment |\n| KPI gauge | NPS score, response rate |\n\n**Likert color scale (mandatory):**\nStrongly Disagree=#d32f2f, Disagree=#ef5350, Neutral=#9e9e9e, Agree=#66bb6a, Strongly Agree=#2e7d32\n\n### 5. NPS Calculation\n\nPromoters (9-10) minus Detractors (0-6), divided by total, times 100.\nGreen (50+): Excellent. Yellow (0-49): Good. Red (below 0): Needs attention.\n\n### 6. Cross-Tab Analysis\n\nRows = survey questions. Columns = demographic dimension values.\nCells = mean score with background intensity. Flag low-N segments (<10 respondents).\n\n### 7. Filters\n\n- Date range pickers\n- Department / Team dropdown\n- Region / Location dropdown\n- Role level dropdown\n- Question selector for cross-tab focus\n\nAll filters update every chart, KPI, and table simultaneously.\n\nCHART.JS LOADING (MANDATORY):\n1. Include Chart.js CDN in <head>: <script src="https://cdn.jsdelivr.net/npm/chart.js"></script>\n2. ALL chart initialization code MUST be inside an IIFE placed immediately after its <canvas>: (function(){ new Chart(...); })();\n3. Every <canvas> element must have a unique id attribute and explicit height: <canvas id="chart1" height="200" style="height:200px !important; max-height:200px;"></canvas>\n4. Chart initialization must reference canvas by getElementById, never querySelector.\n5. If Chart.js fails to load, show a text fallback with the data in a table.\n6. NEVER use import statements for Chart.js — use the global Chart object from CDN.\n7. NEVER use type:"horizontalBar" — use type:"bar" with options.indexAxis:"y" instead.',
  true
WHERE NOT EXISTS (
  SELECT 1 FROM skill_registry
  WHERE plugin_name = 'data' AND skill_name = 'survey-analytics'
);

-- ============================================================================
-- 2. Youth Sports League Manager (operations plugin)
-- ============================================================================

INSERT INTO skill_registry (plugin_name, skill_name, team_function, description, content, is_active)
SELECT
  'operations',
  'youth-sports-league',
  'operations',
  'Build an interactive youth sports league dashboard with team rosters, game schedules, score tracking, standings, and coach availability.',
  E'---\nname: youth-sports-league\ndescription: Build an interactive youth sports league management dashboard with team rosters, game schedules, score tracking, standings, and coach availability.\nargument-hint: "<league name, sport, or season>"\n---\n\n# /youth-sports-league - Youth Sports League Manager\n\nBuild a self-contained interactive HTML dashboard for managing a youth sports league — team rosters, game schedules, live score tracking, standings tables, and coach/volunteer availability.\n\n## Usage\n\n```\n/youth-sports-league <league name, sport, or season details>\n```\n\n## Workflow\n\n### 1. Understand the League\n\nDetermine:\n- **Sport**: Soccer, basketball, baseball, flag football, volleyball\n- **Age divisions**: U8, U10, U12, U14, etc.\n- **Number of teams**: Typically 6-16 per division\n- **Season structure**: Regular season length, playoffs, tournaments\n- **Roster rules**: Min/max players, playing time requirements\n\n### 2. Dashboard Layout\n\n```\n+------------------------------------------------------+\n| [League Name] - [Season]             [Division]      |\n+------------+------------+------------+---------------+\n| Teams      | Players    | Games      | Games         |\n| Registered | Registered | Played     | Remaining     |\n+------------------------------------------------------+\n| Standings Table (W-L-D, Pts, GF, GA, GD)            |\n+------------------------+-----------------------------+\n| Upcoming Schedule      | Recent Results              |\n| (next 5 games)         | (last 5 games)              |\n+------------------------+-----------------------------+\n| Goals/Points by Team   | Coach Availability          |\n| (bar chart)            | (calendar heatmap)          |\n+------------------------------------------------------+\n| Team Roster View (expandable per team)               |\n+------------------------------------------------------+\n```\n\n### 3. Key Features\n\n**Standings Calculation:**\nWin=3pts, Draw=1pt, Loss=0pts. Sort by points desc, goal diff desc, goals for desc.\n\n**Schedule View:**\nDate, time, field, home vs away with team color badges. Filter by team.\n\n**Roster View:**\nExpandable accordion per team: player name, number, position, age, parent contact.\n\n**Coach Availability:**\nCalendar grid: rows=coaches, columns=game dates. Green=available, red=unavailable.\nAlert if any date has fewer than required coaches.\n\n### 4. Chart Types\n\n| Chart | Purpose |\n|-------|--------|\n| Bar | Goals/points scored per team (colored by team) |\n| Stacked bar | W/L/D per team (green/red/gray) |\n| Line | Goals scored per week (season trend) |\n| Heatmap | Coach availability calendar |\n\n### 5. Data Models\n\nTeams: id, name, division, color, coach name/phone/email\nPlayers: id, teamId, name, number, position, age, parent contact\nSchedule: id, week, date, time, home/away teams, field, scores, status\nCoach availability: coach, date, available boolean\n\nCHART.JS LOADING (MANDATORY):\n1. Include Chart.js CDN in <head>: <script src="https://cdn.jsdelivr.net/npm/chart.js"></script>\n2. ALL chart initialization code MUST be inside an IIFE placed immediately after its <canvas>: (function(){ new Chart(...); })();\n3. Every <canvas> element must have a unique id attribute and explicit height: <canvas id="chart1" height="200" style="height:200px !important; max-height:200px;"></canvas>\n4. Chart initialization must reference canvas by getElementById, never querySelector.\n5. If Chart.js fails to load, show a text fallback with the data in a table.\n6. NEVER use import statements for Chart.js — use the global Chart object from CDN.\n7. NEVER use type:"horizontalBar" — use type:"bar" with options.indexAxis:"y" instead.',
  true
WHERE NOT EXISTS (
  SELECT 1 FROM skill_registry
  WHERE plugin_name = 'operations' AND skill_name = 'youth-sports-league'
);

-- ============================================================================
-- 3. Sales CRM Dashboard (sales plugin)
-- ============================================================================

INSERT INTO skill_registry (plugin_name, skill_name, team_function, description, content, is_active)
SELECT
  'sales',
  'crm-dashboard',
  'sales',
  'Build an interactive sales CRM dashboard with pipeline by stage, contacts list, activity feed, and revenue trend charts.',
  E'---\nname: crm-dashboard\ndescription: Build an interactive sales CRM dashboard with pipeline by stage, contacts list, activity feed, and revenue trend charts.\nargument-hint: "<CRM data source or sales team>"\n---\n\n# /crm-dashboard - Sales CRM Dashboard\n\nBuild a self-contained interactive HTML dashboard for sales CRM data — pipeline visualization by stage, contacts directory, activity feed, revenue trend charts, and rep performance.\n\n## Usage\n\n```\n/crm-dashboard <description of CRM data or sales team>\n```\n\n## Workflow\n\n### 1. Understand the Sales Org\n\nDetermine:\n- **Sales model**: B2B enterprise, mid-market, SMB, B2C, PLG\n- **Pipeline stages**: Lead, Qualified, Demo, Proposal, Negotiation, Closed Won/Lost\n- **Rep structure**: Individual reps, teams, territories\n- **Revenue targets**: Monthly/quarterly quotas\n- **Key metrics**: ARR/MRR, ACV, deal velocity, win rate, avg deal size\n\n### 2. Dashboard Layout\n\n```\n+------------------------------------------------------+\n| Sales CRM Dashboard                  [Filters]       |\n+------------+------------+------------+---------------+\n| Pipeline   | Weighted   | Win Rate   | Avg Deal      |\n| Value      | Pipeline   |            | Cycle (days)  |\n+------------------------------------------------------+\n| Pipeline Funnel by Stage (horizontal bar)            |\n+------------------------+-----------------------------+\n| Revenue Trend          | Deals by Rep                |\n| (actual vs target)     | (stacked: won/open/lost)    |\n+------------------------+-----------------------------+\n| Activity Feed          | Contacts List               |\n| (calls, emails, mtgs)  | (searchable, sortable)      |\n+------------------------------------------------------+\n| Deal Pipeline Table (sortable)                       |\n+------------------------------------------------------+\n```\n\n### 3. Pipeline Funnel\n\nHorizontal bars per stage. Width proportional to deal count or value.\nStage name, count, and value as labels. Conversion rates between stages.\nColor progression: cool blues (early) to warm oranges (late), green (won), red (lost).\n\n### 4. Revenue Trend\n\nLine chart: months on x-axis, actual closed revenue as solid line, quota as dashed line.\nShaded area between actual and target. Current month projection annotation.\n\n### 5. KPI Calculations\n\n- Pipeline Value: sum of open deal amounts\n- Weighted Pipeline: sum of (amount x probability) for open deals\n- Win Rate: closed-won / (closed-won + closed-lost) x 100\n- Avg Deal Size: total closed-won revenue / count of won deals\n- Avg Cycle Days: mean days from created to closed for won deals\n\n### 6. Activity Feed\n\nChronological list: icon per type (phone/envelope/calendar), rep name, contact, company, relative timestamp, notes preview.\n\n### 7. Contacts List\n\nSearchable directory: name, company, title, email, phone, last contact date, deal count, source.\n\n### 8. Chart Types\n\n| Chart | Purpose |\n|-------|--------|\n| Horizontal bar | Pipeline funnel by stage |\n| Line + dashed | Revenue actual vs target |\n| Stacked bar | Deals by rep (won/open/lost) |\n| Doughnut | Pipeline composition by stage |\n| Bar | Activity volume by rep or week |\n\n### 9. Filters\n\n- Rep dropdown\n- Stage multi-select\n- Date range pickers\n- Deal size range\n\nAll filters update every chart, KPI, feed, and table simultaneously.\n\n### 10. HubSpot Integration\n\nWhen connected via Nango: deals, contacts, and activities pulled automatically.\nPipeline stages mapped from HubSpot deal stages. Engagement data included.\n\nCHART.JS LOADING (MANDATORY):\n1. Include Chart.js CDN in <head>: <script src="https://cdn.jsdelivr.net/npm/chart.js"></script>\n2. ALL chart initialization code MUST be inside an IIFE placed immediately after its <canvas>: (function(){ new Chart(...); })();\n3. Every <canvas> element must have a unique id attribute and explicit height: <canvas id="chart1" height="200" style="height:200px !important; max-height:200px;"></canvas>\n4. Chart initialization must reference canvas by getElementById, never querySelector.\n5. If Chart.js fails to load, show a text fallback with the data in a table.\n6. NEVER use import statements for Chart.js — use the global Chart object from CDN.\n7. NEVER use type:"horizontalBar" — use type:"bar" with options.indexAxis:"y" instead.',
  true
WHERE NOT EXISTS (
  SELECT 1 FROM skill_registry
  WHERE plugin_name = 'sales' AND skill_name = 'crm-dashboard'
);

